-- MITTHAN DI HATTI — Complete Site Blueprint / Replication Guide
-- Run this in Supabase SQL Editor (Dashboard → SQL Editor)
-- ============================================================

-- 1. Create the blueprint table
CREATE TABLE IF NOT EXISTS public.app_blueprint (
  id bigint generated by default as identity primary key,
  section text not null,
  item_name text not null,
  type text not null,
  description text not null,
  location text not null,
  details jsonb default '{}'::jsonb,
  sort_order int default 0,
  created_at timestamptz default now()
);

-- Enable RLS (read-only for anon)
ALTER TABLE public.app_blueprint ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Anyone can read blueprint" ON public.app_blueprint;
CREATE POLICY "Anyone can read blueprint" ON public.app_blueprint
  FOR SELECT USING (true);

-- Enable Realtime
ALTER PUBLICATION supabase_realtime ADD TABLE public.app_blueprint;

-- 2. Seed the full blueprint
INSERT INTO public.app_blueprint (section, item_name, type, description, location, details, sort_order) VALUES

