-- ============ DATABASE ============
('Database', 'orders Table', 'table', 'Main orders table. Stores every order from both QR (customer) and Counter (admin billing). JSONB items array holds line items. Has RLS enabled — anon can INSERT (for customer orders) but only authenticated can SELECT/UPDATE. Realtime enabled for dashboard.', 'Supabase project: qlidbwmdrzhrhbndmcwy', '{"columns": ["id(uuid,pk)", "items(jsonb)", "total(numeric)", "subtotal(numeric)", "discount(numeric)", "payment_mode(text)", "order_type(text)", "table_no(text)", "status(text)", "paid(boolean)", "paid_at(timestamptz)", "order_date(date)", "source(text)", "created_at(timestamptz)", "notes(text)"], "realtime": true}', 55),
('Database', 'menu_overrides Table', 'table', 'Stores all menu modifications: price changes, availability toggles, custom items, deletions. Overlays on top of static menu-data.js. Fields: id (matches menu item ID for overrides, UUID for custom), name, price, half_price, unit, category_id, category, available, is_custom, deleted, created_at. Realtime enabled for menu grids.', 'Supabase project: qlidbwmdrzhrhbndmcwy', '{"columns": ["id(text,pk)", "name(text)", "price(numeric)", "half_price(numeric)", "unit(text)", "category_id(numeric)", "category(text)", "available(boolean)", "is_custom(boolean)", "deleted(boolean)", "created_at(timestamptz)"], "realtime": true}', 56),
('Database', 'app_blueprint Table', 'table', 'This table! Contains the complete site replication guide with every page, component, button, database table, and feature documented. Readable by anyone (RLS policy allows anon SELECT).', 'this SQL file + supabase_seed_blueprint.sql', '{"columns": ["id(bigint,pk)", "section(text)", "item_name(text)", "type(text)", "description(text)", "location(text)", "details(jsonb)", "sort_order(int)", "created_at(timestamptz)"], "realtime": true}', 57),

('Database', 'RLS Policies', 'config', 'orders: anon can INSERT, authenticated (service_role) can SELECT/UPDATE. menu_overrides: anon can SELECT, upsert/delete from client (no RLS check on service key — actually these run as anon with permissive RLS). app_blueprint: anyone can SELECT.', 'Supabase Dashboard → Authentication → Policies', '{"note": "menu_overrides upsert works because RLS defaults to permissive for anon on this table"}', 58),
('Database', 'Realtime Publications', 'config', 'Three tables added to supabase_realtime publication: orders, menu_overrides, app_blueprint. Enables realtime subscriptions via postgres_changes.', 'Supabase Dashboard → Database → Replication', '{"tables": ["orders", "menu_overrides", "app_blueprint"]}', 59),

