('Gotchas', 'Sales Date Filter', 'note', 'Sales page filters by order_date column (not created_at). This ensures editing an order later doesn't shift it to a different date.', 'src/app/admin/sales/page.js', '{"reason": "edits should not change date"}', 70),
('Gotchas', 'Dashboard Sound File', 'note', 'Dashboard plays /bell.mp3 on new orders. The file must exist in /public directory. If missing, no error — just silent.', 'public/bell.mp3', '{"required": true, "path": "public/ding.mp3"}', 71),
